import React from 'react';
import { View, Text } from 'react-native';
import { Biometrics } from 'react-native-biometrics';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AuthenticatedFlag = 'authenticated';

class LoginScreen extends React.Component {
  constructor(props) {
    super(props);
    this.state = { authenticated: false };
  }

  async componentDidMount() {
    const isAuthenticated = await AsyncStorage.getItem(AuthenticatedFlag);
    if (isAuthenticated === 'true') {
      this.setState({ authenticated: true });
    }
  }

  handleBiometricAuthentication = async () => {
    try {
      const isAuthenticated = await Biometrics.authenticate();
      if (isAuthenticated) {
        await AsyncStorage.setItem(AuthenticatedFlag, 'true');
        this.setState({ authenticated: true });
      } else {
        throw new Error('Biometric authentication failed');
      }
    } catch (error) {
      console.log(error);
    }
  };

  render() {
    if (this.state.authenticated) {
      return <Text>You are authenticated!</Text>;
    } else {
      return (
        <View>
          <Button onPress={this.handleBiometricAuthentication} title="Authenticate" />
        </View>
      );
    }
  }
}